/** Route form chứng từ full-page (toolbar + pageVoucher scroll nội bộ). */
const VOUCHER_FORM_SEGMENTS = new Set([
  'pt',
  'pc',
  'phieu-thu',
  'phieu-chi',
  'pdc',
  'pnm',
  'pnm-xt',
  'hdmh-dv',
  'tam-ung',
  'pkt',
]);

export function isVoucherFormPath(pathname: string): boolean {
  const parts = pathname.split('/').filter(Boolean);
  if (parts.length < 3) return false;
  const [domain, module, action] = parts;
  if (domain !== 'kt') return false;
  if (!VOUCHER_FORM_SEGMENTS.has(module)) return false;
  return action === 'them' || action.length > 0;
}
